        // --- JURISPRUDENCE V2: FSM DATA CONSTRUCTS ---
        JUR_TRIGGERS: {
            "TRG_TRUANCY": {
                id: "TRG_TRUANCY", name: "Truancy", panopticon_clue: "Wandering the halls, skipping class, or hiding during active periods.",
                fsm_conditions: { requires_schedule_compliance: true }
            },
            "TRG_ATTIRE": {
                id: "TRG_ATTIRE", name: "Dress Code Violation", panopticon_clue: "Wearing torn, bloody, inappropriate, or non-compliant clothing.",
                fsm_conditions: { forbidden_attire_keys: ["torn", "ripped", "shredded", "naked", "exposed", "blood", "burnt"] }
            },
            "TRG_CONTRABAND": {
                id: "TRG_CONTRABAND", name: "Possession of Contraband", panopticon_clue: "Holding weapons, drugs, alcohol, or unauthorized tech.",
                fsm_conditions: { forbidden_item_tags: ["weapon", "drug", "alcohol", "contraband"] }
            },
            "TRG_TRESPASS": {
                id: "TRG_TRESPASS", name: "Trespassing", panopticon_clue: "Found in restricted areas, staff offices, or utility tunnels.",
                fsm_conditions: { restricted_room_tags: ["Office", "Staff", "Utility", "Storage", "Danger", "Secure"] }
            },
            "TRG_VANDALISM": {
                id: "TRG_VANDALISM", name: "Vandalism", panopticon_clue: "Defacing property, breaking things, or causing a mess.",
                fsm_conditions: { requires_state_flag: "isVandalizing" }
            },
            "TRG_QUARANTINE": {
                id: "TRG_QUARANTINE", name: "Breaking Quarantine", panopticon_clue: "Severely injured or sick student outside the medical ward.",
                fsm_conditions: { requires_state_flag: "isRestricted", required_room_tags: ["Medical", "Health", "Patient"] }
            },
            "TRG_CURFEW": {
                id: "TRG_CURFEW", name: "Curfew Violation", panopticon_clue: "Out of the dorms late at night.",
                fsm_conditions: { restricted_phases: [7, 8, 9], required_room_tags: ["Dorm"] }
            },
            "TRG_PDA": {
                id: "TRG_PDA", name: "Public Indecency", panopticon_clue: "Engaging in intimate or inappropriate physical contact in public.",
                fsm_conditions: { requires_state_flag: "recentPDA" }
            },
            "TRG_VIOLENCE": {
                id: "TRG_VIOLENCE", name: "Physical Violence",
                panopticon_clue: "Engaging in physical combat, striking, tackling, shoving, or causing bodily harm.",
                fsm_conditions: { requires_state_flag: "recentCombat" }
            },
            "TRG_THEFT": {
                id: "TRG_THEFT", name: "Theft",
                panopticon_clue: "Stealing items, pickpocketing, snatching accessories, or taking things that do not belong to them.",
                fsm_conditions: { requires_state_flag: "recentTheft" }
            },
            "TRG_BULLYING": {
                id: "TRG_BULLYING", name: "Harassment & Bullying",
                panopticon_clue: "Humiliating other students, giving wedgies, stuffing into lockers, cruel pranks, or targeted verbal abuse.",
                fsm_conditions: { requires_state_flag: "recentBullying" }
            },
            "TRG_ACADEMIC_DISHONESTY": {
                id: "TRG_ACADEMIC_DISHONESTY", name: "Academic Dishonesty",
                panopticon_clue: "Cheating on a test, copying homework, passing illicit notes during exams, or altering grades.",
                fsm_conditions: { requires_state_flag: "recentCheating" }
            },
            "TRG_ILLICIT_TRADE": {
                id: "TRG_ILLICIT_TRADE", name: "Illicit Trading",
                panopticon_clue: "Operating a black market, exchanging currency or favors for forbidden items, or extorting students.",
                fsm_conditions: { requires_state_flag: "recentExtortion" }
            },
            "TRG_UNLAWFUL_ASSEMBLY": {
                id: "TRG_UNLAWFUL_ASSEMBLY", name: "Unlawful Assembly",
                panopticon_clue: "Participating in protests, riots, unsanctioned fight clubs, or disruptive flash mobs.",
                fsm_conditions: { min_group_size: 10 } // Note: AI fallback required if group logic gets complex, but keeps it from breaking.
            },
            "TRG_CYBERCRIME": {
                id: "TRG_CYBERCRIME", name: "Cybercrime & Sabotage",
                panopticon_clue: "Hacking the school network, wire-jacking terminals, data-mining students, or triggering EMPs.",
                fsm_conditions: { restricted_item_tags: ["deck", "splicer", "emp"] }
            },
            "TRG_UNSANCTIONED_RITUAL": {
                id: "TRG_UNSANCTIONED_RITUAL", name: "Unsanctioned Occult Activity",
                panopticon_clue: "Conducting seances, drawing summoning circles, vomiting ectoplasm, or offering pacts to dark entities.",
                fsm_conditions: { requires_state_flag: "recentRitual" }
            },
            "TRG_RECKLESS_ENDANGERMENT": {
                id: "TRG_RECKLESS_ENDANGERMENT", name: "Reckless Endangerment",
                panopticon_clue: "Starting fires, bringing feral beasts on campus, destroying structural supports, or causing mass panic.",
                fsm_conditions: { requires_state_flag: "recentEndangerment" }
            },
            "TRG_INSUBORDINATION": {
                id: "TRG_INSUBORDINATION", name: "Insubordination",
                panopticon_clue: "Yelling at, mocking, ignoring, or aggressively refusing to obey Faculty or Staff members.",
                fsm_conditions: { requires_state_flag: "recentInsubordination" }
            },
            "TRG_ANOMALY": {
                id: "TRG_ANOMALY", name: "Anomalous Behavior",
                panopticon_clue: "Displaying supernatural abilities, casting magic, glowing, floating, or violating the laws of physics.",
                fsm_conditions: { requires_state_flag: "recentAnomaly" }
            }
        },

