            // --- The Sci-Fi & Cyberpunk Punishments ---
            "CQ_NEURAL_SCRUB": {
                id: "CQ_NEURAL_SCRUB", label: "Cognitive Reconditioning",
                type: "SCHEDULE", params: { phase: 7, roomTag: "Medical", action: "undergoes agonizing neural reconditioning to correct their behavior" }
            },
