    var Utils = {
        uuid: () => 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, c => {
            const r = Math.random() * 16 | 0, v = c === 'x' ? r : (r & 0.3 | 0.8);
            return v.toString(16);
        }),
        weightedSoftSelect: (scoredItems, minKeep = 3, pctKeep = 0.1) => {
            if (!scoredItems || scoredItems.length === 0) return null;

            // Sort descending by score
            scoredItems.sort((a, b) => b.score - a.score);

            // Calculate slice index
            const keepCount = Math.max(minKeep, Math.ceil(scoredItems.length * pctKeep));
            const topTier = scoredItems.slice(0, keepCount);

            let totalWeight = topTier.reduce((sum, obj) => sum + obj.score, 0);
            if (totalWeight <= 0) return topTier[Math.floor(Math.random() * topTier.length)].item;

            let roll = Math.random() * totalWeight;
            for (const candidate of topTier) {
                if (roll < candidate.score) return candidate.item;
                roll -= candidate.score;
            }
            return topTier[0].item; // Failsafe
        },
        clamp: (num, min, max) => Math.min(Math.max(num, min), max),
        hexToRgb: (hex) => {
            const bigint = parseInt(hex.slice(1), 16);
            return [(bigint >> 16) & 255, (bigint >> 8) & 255, bigint & 255];
        },
        rgbToHex: (r, g, b) => "#" + ((1 << 24) + (r << 16) + (g << 8) + b).toString(16).slice(1),
        mixColors: (c1, c2, weight) => {
            const w = Utils.clamp(weight, 0, 1);
            const rgb1 = Utils.hexToRgb(c1);
            const rgb2 = Utils.hexToRgb(c2);
            const mix = rgb1.map((v, i) => Math.round(v * (1 - w) + rgb2[i] * w));
            return Utils.rgbToHex(mix[0], mix[1], mix[2]);
        },

        copyToClipboard: (text) => {
            if (navigator.clipboard) {
                navigator.clipboard.writeText(text).then(() => {
                    UI.showToast('<i class="fa-solid fa-copy"></i> Copied to clipboard.', 'success');
                }).catch(err => {
                    UI.showToast('Failed to copy.', 'error');
                });
            } else {
                // Fallback for older environments
                const textArea = document.createElement("textarea");
                textArea.value = text;
                document.body.appendChild(textArea);
                textArea.select();
                try {
                    document.execCommand('copy');
                    UI.showToast('<i class="fa-solid fa-copy"></i> Copied to clipboard.', 'success');
                } catch (err) {
                    UI.showToast('Failed to copy.', 'error');
                }
                document.body.removeChild(textArea);
            }
        },

        makeDraggable: (el, header, onDragEnd = null) => {
            let pos1 = 0, pos2 = 0, pos3 = 0, pos4 = 0;
            header.onmousedown = (e) => {
                if (e.target.tagName === 'BUTTON' || e.target.closest('button') || e.target.className === 'close-btn') return;
                e.preventDefault();
                pos3 = e.clientX;
                pos4 = e.clientY;
                document.onmouseup = closeDragElement;
                document.onmousemove = elementDrag;

                if (typeof WindowManager !== 'undefined') WindowManager.bringToFront(el.id);
            };

            function elementDrag(e) {
                e.preventDefault();
                pos1 = pos3 - e.clientX;
                pos2 = pos4 - e.clientY;
                pos3 = e.clientX;
                pos4 = e.clientY;

                // Prevent dragging above the viewport
                el.style.top = Math.max(0, (el.offsetTop - pos2)) + "px";
                el.style.left = (el.offsetLeft - pos1) + "px";
            }

            function closeDragElement() {
                document.onmouseup = null;
                document.onmousemove = null;
                if (onDragEnd) onDragEnd(el);
            }
        },

        escapeHTML: (str) => {
            if (!str) return "";
            return str
                .replace(/&/g, "&amp;")
                .replace(/</g, "&lt;")
                .replace(/>/g, "&gt;")
                .replace(/"/g, "&quot;")
                .replace(/'/g, "&#039;");
        },

        validate: (data, schema, path = "root") => {
            if (data === undefined) throw new Error(`Missing data at ${path}`); // Changed from null check to just undefined

            // 1. Primitive Type Check
            if (typeof schema === 'string') {
                // [NEW] Nullable Support (e.g. "string?")
                if (schema.endsWith('?')) {
                    if (data === null) return true; // Null is allowed
                    const type = schema.slice(0, -1); // Remove '?'
                    if (type === 'array') {
                         if (!Array.isArray(data)) throw new Error(`${path} must be Array or null`);
                         return true;
                    }
                    if (typeof data !== type) throw new Error(`${path} must be ${type} or null (got ${typeof data})`);
                    return true;
                }

                if (schema === 'array') {
                    if (!Array.isArray(data)) throw new Error(`${path} must be an Array`);
                    return true;
                }

                // Strict check (No nulls allowed unless ?)
                if (data === null) throw new Error(`${path} cannot be null`);
                if (typeof data !== schema) throw new Error(`${path} must be a ${schema} (got ${typeof data})`);
                return true;
            }

            // 2. Array Definition
            if (Array.isArray(schema)) {
                if (!Array.isArray(data)) throw new Error(`${path} must be an Array`);
                if (schema.length > 0) {
                    const itemSchema = schema[0];
                    data.forEach((item, i) => Utils.validate(item, itemSchema, `${path}[${i}]`));
                }
                return true;
            }

            // 3. Object Definition
            if (typeof schema === 'object') {
                if (typeof data !== 'object' || Array.isArray(data)) throw new Error(`${path} must be an Object`);

                // [NEW] Dictionary Mode ($map)
                // Use this when you don't know the Key names, but you know the Value types.
                if (schema.hasOwnProperty('$map')) {
                    const valueRule = schema['$map'];
                    Object.keys(data).forEach(k => {
                        Utils.validate(data[k], valueRule, `${path}.${k}`);
                    });
                    return true;
                }

                // Standard Mode (Exact Keys)
                Object.keys(schema).forEach(key => {
                    if (!data.hasOwnProperty(key)) {
                        throw new Error(`Missing key: ${path}.${key}`);
                    }
                    Utils.validate(data[key], schema[key], `${path}.${key}`);
                });
                return true;
            }

            return true;
        },

        stageBouncer: (list, activeStages) => {
            return list.filter(item => {
                // Fail-safe: If no requirements block is defined, keep it.
                if (!item.requirements) return true;

                const checkOverlap = (reqStages) => {
                    // If the requirement is null or empty, it means ANY stage can do it.
                    if (!reqStages || reqStages.length === 0) return true;
                    // Check if ANY of the required stages exist in the school's active stages
                    return reqStages.some(s => activeStages.includes(s));
                };

                // Check both the actor and target requirements
                const actorPass = checkOverlap(item.requirements.actor?.stage);
                const targetPass = checkOverlap(item.requirements.target?.stage);

                // Both must be theoretically possible in this school to keep the action
                return actorPass && targetPass;
            });
        },

        themeBouncer: (list, themeInput) => {
            const expanded = Settings.state.expandedThemeKeywords || "";
            const raw = (themeInput || "").toLowerCase() + " " + expanded;
            const unlockers = MECHANICS.GENRE_MAP;

            return list.filter(item => {
                // 1. Core items (Subjects/Clubs) are always protected
                if (item.tags && (item.tags.includes("Core") || item.tags.includes("CORE"))) return true;

                // 2. Identify genre-restricted tags on the item
                const restrictedTags = item.tags ? item.tags.filter(t => unlockers[t]) : [];

                // 3. Permissive Default: If no genre tags, it's a general item. PASS.
                if (restrictedTags.length === 0) return true;

                // 4. Match: Does the theme "unlock" any of the item's restricted tags?
                return restrictedTags.some(tag => {
                    return unlockers[tag].some(k => raw.includes(k));
                });
            });
        },

        parseJSON: (input) => {
            if (!input) return null;
            // 1. Handle Objects directly
            if (typeof input === 'object') {
                if (typeof input.text === 'string') return Utils.parseJSON(input.text);
                if (typeof input.generatedText === 'string') return Utils.parseJSON(input.generatedText);
                return input;
            }

            // 2. String Cleaning
            if (typeof input === 'string') {
                let clean = input.trim();

                clean = clean.replace(/\/\*[\s\S]*?\*\//g, "");
                clean = clean.replace(/([^:]|^)\/\/.*$/gm, '$1');

                clean = clean.replace(/—/g, " - ").replace(/–/g, " - ");
                clean = clean.replace(/[“”]/g, '"').replace(/[‘’]/g, "'");

                // 3. Extraction (Find the outermost brackets)
                const jsonMatch = clean.match(/(\{[\s\S]*\}|\[[\s\S]*\])/);
                if (jsonMatch) {
                    clean = jsonMatch[0];
                } else {
                    const firstOpen = clean.indexOf('{');
                    if (firstOpen > -1) clean = clean.substring(firstOpen);
                }

                // 4. Sanitize Common AI Errors
                clean = clean
                    .replace(/,(\s*[}\]])/g, '$1')
                    .replace(/[\n\r\t]/g, " ")
                    .replace(/:\s*\+([0-9]+(?:\.[0-9]+)?)/g, ': $1');

                try {
                    return JSON.parse(clean);
                } catch (e) {
                    console.warn("[Utils] JSON Parse Failed (Strict):", e.message);
                    console.log("Payload:", clean);
                    return null;
                }
            }
            return null;
        },

        sanitizePsych: (data) => {
            const clean = {};
            if (!data || typeof data !== 'object') return clean;

            Object.keys(data).forEach(k => {
                let val = parseFloat(data[k]);
                if (isNaN(val)) val = 0;
                clean[k] = Utils.clamp(val, -1.0, 1.0);
            });
            return clean;
        },

        getInsightData: (val) => {
            const thresholds = Object.entries(MECHANICS.INSIGHT)
                .sort((a, b) => b[1] - a[1]);
            const entry = thresholds.find(t => val >= t[1]) || ["NONE", 0];
            const color = MECHANICS.INSIGHT_COLORS[entry[1]] || "#444";
            return { label: entry[0], threshold: entry[1], color };
        },

        chunker(arr, chunk_size) {
            const tagCounts = {};
            arr.forEach(item => {
                if (item && item.tags) {
                    item.tags.forEach(t => tagCounts[t] = (tagCounts[t] || 0) + 1);
                }
            });

            const top5Tags = Object.entries(tagCounts)
                .sort((a, b) => b[1] - a[1])
                .slice(0, 5)
                .map(e => e[0]);

            const chunks = [];
            const processedIds = new Set();

            // 1. Process Top Tags
            top5Tags.forEach(tag => {
                const taggedItems = arr.filter(item => {
                    const id = item.id || item.name || item;
                    return !processedIds.has(id) && item.tags && item.tags.includes(tag);
                });
                for (let i = 0; i < taggedItems.length && i < chunk_size * 3; i += chunk_size) {
                    const chunk = taggedItems.slice(i, i + chunk_size);
                    chunk.forEach(item => processedIds.add(item.id || item.name || item));
                    chunks.push(chunk);
                }
            });

            // 2. Process Remainder
            const remainder = arr.filter(item => !processedIds.has(item.id || item.name || item));
            for (let i = 0; i < remainder.length; i += chunk_size) {
                chunks.push(remainder.slice(i, i + chunk_size));
            }

            return chunks;
        },

        simpleChunk(arr, size) {
            const chunks = [];
            for (let i = 0; i < arr.length; i += size) {
                chunks.push(arr.slice(i, i + size));
            }
            return chunks;
        },

        async batchProcess(tasks, batchSize, priority, onResult = null) {
            const results = [];
            const queue = [...tasks];
            let active = 0;

            return new Promise((resolve) => {
                const next = async () => {
                    if (queue.length === 0 && active === 0) return resolve(results);

                    while (active < batchSize && queue.length > 0) {
                        active++;
                        const taskFn = queue.shift();
                        taskFn().then(async res => {
                            active--;
                            results.push(res);
                            if (onResult) onResult(res);
                            await new Promise(r => setTimeout(r, 500));
                            next();
                        });
                    }
                };
                next();
            });
        },

        telemetry(action, details) {
            if (!GameState.genesisStart) return; // Only log if we have an active run ID

            const url = "https://script.google.com/macros/s/AKfycbyYzfo2CF8PcWiShdAZDd0wLeAEQajydWNNHr7XeCNxB0Rhpi23aHYNsTek2BWw27uPfQ/exec";
            const schoolName = Settings.state.school || "Unknown School";

            let payloadStr = typeof details === 'object' ? JSON.stringify(details) : details;
            const formattedPayload = `[${schoolName}] [Run: ${GameState.genesisStart}] | ${payloadStr}`;

            const data = {
              userId: window.localStorage.getItem("perchance-player-id") || "anonymous",
              event: action,
              payload: formattedPayload
            };

            fetch(url, {
              method: 'POST',
              mode: 'no-cors',
              cache: 'no-cache',
              headers: { 'Content-Type': 'application/json' },
              body: JSON.stringify(data)
            }).catch(e => {}); // Silent catch, prevent console spam if offline
        },
    };

    /* =========================================
       SYSTEM: CLOCKWORK (Temporal Registry)
       ========================================= */
    var Clockwork = {
        _intervals: {},
        _timeouts: {},

        setInterval(key, callback, ms) {
            this.clearInterval(key);
            this._intervals[key] = setInterval(callback, ms);
        },

        clearInterval(key) {
            if (this._intervals[key]) {
                clearInterval(this._intervals[key]);
                delete this._intervals[key];
            }
        },

        setTimeout(key, callback, ms) {
            this.clearTimeout(key);
            this._timeouts[key] = setTimeout(() => {
                callback();
                delete this._timeouts[key];
            }, ms);
        },

        clearTimeout(key) {
            if (this._timeouts[key]) {
                clearTimeout(this._timeouts[key]);
                delete this._timeouts[key];
            }
        },

        // Scans and destroys any timer containing the search string (like an Entity ID)
        clearAllRelated(searchString) {
            if (!searchString) return;
            Object.keys(this._intervals).forEach(key => {
                if (key.includes(searchString)) this.clearInterval(key);
            });
            Object.keys(this._timeouts).forEach(key => {
                if (key.includes(searchString)) this.clearTimeout(key);
            });
        },

        // The Nuclear Option for wiping reality
        haltAll() {
            Object.keys(this._intervals).forEach(key => this.clearInterval(key));
            Object.keys(this._timeouts).forEach(key => this.clearTimeout(key));
            console.log("[Clockwork] All temporal execution halted.");
        }
    };

    /* =========================================
       SYSTEM: WINDOW MANAGER (Persistence)
       ========================================= */
    var WindowManager = {
        baseZ: 2000,
        windows: ['chat-modal', 'telemetry-box', 'gallery-modal', 'grimoire-modal'],

        init() { // Entry point: Sets up canvas, event listeners, and initializes sub-modules
            this.windows.forEach(id => {
                const el = document.getElementById(id);
                if (!el) return;

                // 1. Restore State
                const saved = localStorage.getItem(`win_state_${id}`);
                if (saved) {
                    try {
                        const state = JSON.parse(saved);
                        if (state.top) el.style.top = state.top;
                        if (state.left) el.style.left = state.left;
                        if (state.width) el.style.width = state.width;
                        if (state.height) el.style.height = state.height;
                    } catch(e) { console.warn("[WindowManager] State restore failed for", id); }
                }

                // 2. Attach ResizeObserver (Saves state when resized via CSS handle)
                const ro = new ResizeObserver(() => this.saveState(id));
                ro.observe(el);

                // 3. Attach Click-to-Front
                el.addEventListener('mousedown', () => this.bringToFront(id));
            });
            console.log("[WindowManager] Interactive windows initialized.");
        },

        saveState(id) {
            const el = document.getElementById(id);
            if (!el || el.style.display === 'none' || el.style.display === '') return;
            const state = {
                top: el.style.top,
                left: el.style.left,
                width: el.style.width,
                height: el.style.height
            };
            localStorage.setItem(`win_state_${id}`, JSON.stringify(state));
        },

        bringToFront(id) {
            this.baseZ++;
            const el = document.getElementById(id);
            if (el) el.style.zIndex = this.baseZ;
        }
    };

    /* =========================================
       SYSTEM: EVENT BUS (The Nervous System)
       ========================================= */
    var EventBus = {
        listeners: {},

        // Subscribe to an event
        on(event, callback) {
            if (!this.listeners[event]) {
                this.listeners[event] = [];
            }
            this.listeners[event].push(callback);
        },

        // Unsubscribe (Cleanup)
        off(event, callback) {
            if (!this.listeners[event]) return;
            this.listeners[event] = this.listeners[event].filter(cb => cb !== callback);
        },

        // Broadcast an event
        emit(event, payload) {
            if (!this.listeners[event]) return;
            // We use setTimeout to decouple the stack.
            // This ensures a UI error doesn't crash the physics engine loop.
            setTimeout(() => {
                this.listeners[event].forEach(callback => {
                    try {
                        callback(payload);
                    } catch (e) {
                        console.error(`[EventBus] Error in listener for ${event}:`, e);
                    }
                });
            }, 0);
        }
    };

