                    context: `School: "${schoolName}"\nTheme: "${theme}"\nAvailable Mediums: [${mediumOpts}]\nAvailable Stylizations: [${styleOpts}]`,
                    constraints: [
                        "You MUST select exactly one Medium and one Stylization from the provided lists."
                    ],
                    schemaTemplate: `{ "medium": "Name", "style": "Name" }`,
