                        GameState.player.portrait = img.url;
                        if (!GameState.player.visualMeta.portfolio) GameState.player.visualMeta.portfolio = {};
                        GameState.player.visualMeta.portfolio[0] = img.url;
                        GallerySystem.add(img.url, img.prompt, ["Animus", "Genesis", "Tier 1"]);
                        ConstructorUI.setPortrait('animus', img.url);
