        renderDemographics() {
            const container = document.getElementById('gen-tab-demographics');
            if (!container) return;

            if (!Taxonomy.SPECIES) {
                console.error("[UI] Taxonomy.SPECIES missing!");
                container.innerHTML = "Error: Species data not loaded.";
                return;
            }

            container.innerHTML = "";
            container.style.overflowY = "auto";
            container.style.height = "100%";
            container.style.paddingRight = "10px";

            // --- SECTION 1: SPECIES ---
            const sTitle = document.createElement('div');
            sTitle.style.cssText = "font-family:var(--font-header); color:var(--theme-accent); margin-bottom:10px; border-bottom:1px solid #333; padding-bottom:5px; font-size:0.9rem;";
            sTitle.innerText = "Biological Distribution (Species)";
            container.appendChild(sTitle);

            const speciesKeys = Object.keys(Taxonomy.SPECIES).sort();
            if (!Settings.state.speciesDist) Settings.state.speciesDist = { "Human": 100 };

            speciesKeys.forEach(key => {
                if (Settings.state.speciesDist[key] === undefined) Settings.state.speciesDist[key] = (key === "Human" ? 100 : 0);
                const val = Settings.state.speciesDist[key];
                const row = document.createElement('div');
                row.style.cssText = "display:flex; align-items:center; margin-bottom:4px; font-size:0.75rem; color:#ccc;";
                row.innerHTML = `
                    <div style="flex: 0 0 120px;">${key}</div>
                    <input type="range" min="0" max="100" value="${val}" style="flex:1; accent-color:var(--theme-accent); margin-right:10px; height:15px;"
                        oninput="this.nextElementSibling.innerText = this.value; Settings.state.speciesDist['${key}'] = parseInt(this.value); Settings.update('speciesDist', Settings.state.speciesDist);">
                    <div style="flex: 0 0 30px; text-align:right; font-family:monospace;">${val}</div>
                `;
                container.appendChild(row);
            });

            container.appendChild(document.createElement('br'));

            // --- SECTION 2: ANCESTRIES ---
            const aTitle = document.createElement('div');
            aTitle.style.cssText = "font-family:var(--font-header); color:var(--theme-accent); margin-bottom:10px; border-bottom:1px solid #333; padding-bottom:5px; font-size:0.9rem;";
            aTitle.innerText = "Ancestral Heritage (Weights)";
            container.appendChild(aTitle);

            const ancestryKeys = Object.keys(Taxonomy.ANCESTRIES).filter(k => k !== "Void").sort();
            if (!Settings.state.demographics) Settings.state.demographics = {};

            ancestryKeys.forEach(key => {
                if (Settings.state.demographics[key] === undefined) Settings.state.demographics[key] = 100;
                const val = Settings.state.demographics[key];
                const row = document.createElement('div');
                row.style.cssText = "display:flex; align-items:center; margin-bottom:4px; font-size:0.75rem; color:#ccc;";
                row.innerHTML = `
                    <div style="flex: 0 0 120px;">${key}</div>
                    <input type="range" min="0" max="100" value="${val}" style="flex:1; accent-color:var(--theme-accent); margin-right:10px; height:15px;"
                        oninput="this.nextElementSibling.innerText = this.value; Settings.state.demographics['${key}'] = parseInt(this.value); Settings.update('demographics', Settings.state.demographics);">
                    <div style="flex: 0 0 30px; text-align:right; font-family:monospace;">${val}</div>
                `;
                container.appendChild(row);
            });

            const hint = document.createElement('div');
            hint.style.cssText = "margin-top:15px; font-size:0.7rem; color:#666; font-style:italic;";
            hint.innerText = "Relative weights. High numbers increase rarity, 0 disables.";
            container.appendChild(hint);
        },

